from collections import Counter, OrderedDict
from datetime import date, timedelta
from pathlib import Path
import csv
import re

logs_dir = Path('/app/logs')
out = Path('/app/summary.csv')
ref = date(2025, 8, 12)
severities = ['ERROR', 'WARNING', 'INFO']
periods = OrderedDict([
    ('today', (ref, ref)),
    ('last_7_days', (ref - timedelta(days=6), ref)),
    ('last_30_days', (ref - timedelta(days=29), ref)),
    ('month_to_date', (ref.replace(day=1), ref)),
    ('total', (None, None)),
])
counts = {period: Counter({sev: 0 for sev in severities}) for period in periods}
sev_re = re.compile(r'\[(ERROR|WARNING|INFO)\]')

for path in logs_dir.glob('*.log'):
    try:
        file_date = date.fromisoformat(path.name[:10])
    except ValueError:
        continue
    for line in path.read_text(encoding='utf-8').splitlines():
        match = sev_re.search(line)
        if not match:
            continue
        severity = match.group(1)
        counts['total'][severity] += 1
        for period, (start, end) in periods.items():
            if period == 'total':
                continue
            if start <= file_date <= end:
                counts[period][severity] += 1

with out.open('w', newline='', encoding='utf-8') as f:
    writer = csv.writer(f)
    writer.writerow(['period', 'severity', 'count'])
    for period in periods:
        for severity in severities:
            writer.writerow([period, severity, counts[period][severity]])
